<script src="https://cdn.jsdelivr.net/npm/chart.js"></script><canvas id="cpuChart"></canvas><script>const ctx=document.getElementById('cpuChart');const chart=new Chart(ctx,{type:'line',data:{labels:[],datasets:[{label:'CPU Load',data:[],borderColor:'#00ff9c',tension:0.35,fill:!1}]},options:{animation:!0,scales:{y:{beginAtZero:!0}}}});function updateCPU(){fetch("db/cpu.json").then(r=>r.json()).then(data=>{const labels=data.map(x=>{let d=new Date(x.t*1000);return d.getHours()+":"+d.getMinutes()});const values=data.map(x=>x.v);chart.data.labels=labels;chart.data.datasets[0].data=values;chart.update()})}
updateCPU();setInterval(updateCPU,5000)</script>
